/*
 * NFV VNF Orchestration for IoT
 * Demonstrates Virtual Network Function management and service chaining
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_VNFS 10
#define MAX_SERVICE_CHAIN 5

// VNF Types for IoT
typedef enum {
    VNF_FIREWALL,
    VNF_INTRUSION_DETECTION,
    VNF_DATA_FILTER,
    VNF_ENCRYPTION,
    VNF_ANALYTICS,
    VNF_LOAD_BALANCER
} VNFType;

// VNF Status
typedef enum {
    VNF_ALLOCATED,
    VNF_RUNNING,
    VNF_SCALING,
    VNF_TERMINATED
} VNFStatus;

// Virtual Network Function Structure
typedef struct {
    char vnf_id[20];
    VNFType type;
    VNFStatus status;
    int cpu_cores;      // Required CPU resources
    int memory_mb;      // Required memory
    float load_factor;  // Current load (0.0 - 1.0)
} VNF;

// Service Chain - ordered list of VNFs
typedef struct {
    char chain_id[20];
    VNF *vnfs[MAX_SERVICE_CHAIN];
    int vnf_count;
    char target_app[30];
} ServiceChain;

// NFV Orchestrator
typedef struct {
    VNF vnf_pool[MAX_VNFS];
    int vnf_count;
    ServiceChain chains[5];
    int chain_count;
    int total_cpu_available;
    int total_memory_available;
} NFVOrchestrator;

// Initialize orchestrator
void init_orchestrator(NFVOrchestrator *orch) {
    orch->vnf_count = 0;
    orch->chain_count = 0;
    orch->total_cpu_available = 100;  // 100 CPU units available
    orch->total_memory_available = 512; // 512 MB available
    printf("[NFV] Orchestrator initialized\n");
}

// Get VNF type name
const char* get_vnf_name(VNFType type) {
    switch(type) {
        case VNF_FIREWALL: return "Firewall";
        case VNF_INTRUSION_DETECTION: return "Intrusion Detection";
        case VNF_DATA_FILTER: return "Data Filter";
        case VNF_ENCRYPTION: return "Encryption";
        case VNF_ANALYTICS: return "Analytics";
        case VNF_LOAD_BALANCER: return "Load Balancer";
        default: return "Unknown";
    }
}

// Instantiate a VNF
int instantiate_vnf(NFVOrchestrator *orch, VNFType type, char *app_context) {
    if (orch->vnf_count >= MAX_VNFS) {
        printf("[NFV] Error: VNF pool exhausted\n");
        return -1;
    }

    // Define resource requirements for each VNF type
    int required_cpu, required_mem;
    switch(type) {
        case VNF_FIREWALL:
            required_cpu = 10; required_mem = 256; break;
        case VNF_INTRUSION_DETECTION:
            required_cpu = 20; required_mem = 512; break;
        case VNF_DATA_FILTER:
            required_cpu = 5; required_mem = 128; break;
        case VNF_ENCRYPTION:
            required_cpu = 15; required_mem = 256; break;
        case VNF_ANALYTICS:
            required_cpu = 25; required_mem = 512; break;
        default:
            required_cpu = 10; required_mem = 256;
    }

    // Check resource availability
    if (required_cpu > orch->total_cpu_available || 
        required_mem > orch->total_memory_available) {
        printf("[NFV] Error: Insufficient resources for %s\n", get_vnf_name(type));
        return -1;
    }

    // Create VNF instance
    VNF *new_vnf = &orch->vnf_pool[orch->vnf_count];
    sprintf(new_vnf->vnf_id, "vnf-%d-%s", orch->vnf_count, app_context);
    new_vnf->type = type;
    new_vnf->status = VNF_RUNNING;
    new_vnf->cpu_cores = required_cpu;
    new_vnf->memory_mb = required_mem;
    new_vnf->load_factor = 0.0;

    // Deduct resources
    orch->total_cpu_available -= required_cpu;
    orch->total_memory_available -= required_mem;

    printf("[NFV] Instantiated %s (ID: %s) for %s\n", 
           get_vnf_name(type), new_vnf->vnf_id, app_context);
    printf("       Resources: CPU=%d, Memory=%d MB\n", required_cpu, required_mem);

    orch->vnf_count++;
    return orch->vnf_count - 1;
}

// Create service chain for IoT data processing
void create_service_chain(NFVOrchestrator *orch, char *chain_id, 
                          VNFType *vnf_types, int count, char *app) {
    if (orch->chain_count >= 5 || count > MAX_SERVICE_CHAIN) {
        printf("[NFV] Error: Cannot create service chain\n");
        return;
    }

    ServiceChain *chain = &orch->chains[orch->chain_count];
    strcpy(chain->chain_id, chain_id);
    strcpy(chain->target_app, app);
    chain->vnf_count = 0;

    printf("\n[NFV] Creating Service Chain '%s' for %s\n", chain_id, app);
    printf("       Chain: ");

    for (int i = 0; i < count; i++) {
        // Instantiate each VNF in the chain
        int vnf_idx = instantiate_vnf(orch, vnf_types[i], app);
        if (vnf_idx >= 0) {
            chain->vnfs[chain->vnf_count++] = &orch->vnf_pool[vnf_idx];
            printf("%s", get_vnf_name(vnf_types[i]));
            if (i < count - 1) printf(" -> ");
        }
    }
    printf("\n");

    orch->chain_count++;
}

// Process IoT data through service chain
void process_iot_data(NFVOrchestrator *orch, char *chain_id, 
                      char *iot_data, int data_size) {
    // Find the service chain
    ServiceChain *target_chain = NULL;
    for (int i = 0; i < orch->chain_count; i++) {
        if (strcmp(orch->chains[i].chain_id, chain_id) == 0) {
            target_chain = &orch->chains[i];
            break;
        }
    }

    if (!target_chain) {
        printf("[NFV] Error: Service chain not found\n");
        return;
    }

    printf("\n[IoT Data] Processing '%s' (%d bytes) through %s:\n", 
           iot_data, data_size, chain_id);

    // Process through each VNF in chain
    char *current_data = iot_data;
    for (int i = 0; i < target_chain->vnf_count; i++) {
        VNF *vnf = target_chain->vnfs[i];

        // Simulate VNF processing
        printf("   [%d] %s processing... ", i+1, get_vnf_name(vnf->type));

        // Simulate load increase
        vnf->load_factor += 0.1;
        if (vnf->load_factor > 1.0) vnf->load_factor = 1.0;

        printf("(Load: %.0f%%)\n", vnf->load_factor * 100);

        // Check if scaling needed
        if (vnf->load_factor > 0.8) {
            printf("   [ALERT] High load detected on %s - consider scaling!\n", 
                   vnf->vnf_id);
        }
    }

    printf("   [OK] Data processing complete\n");
}

// Display NFV resources
void display_resources(NFVOrchestrator *orch) {
    printf("\n========== NFV Resource Status ==========\n");
    printf("Available: CPU=%d units, Memory=%d MB\n", 
           orch->total_cpu_available, orch->total_memory_available);
    printf("Active VNFs: %d\n", orch->vnf_count);

    for (int i = 0; i < orch->vnf_count; i++) {
        VNF *vnf = &orch->vnf_pool[i];
        printf("  - %s: %s (Load: %.0f%%)\n", 
               vnf->vnf_id, get_vnf_name(vnf->type), vnf->load_factor * 100);
    }
    printf("========================================\n");
}

int main() {
    printf("======================================\n");
    printf("NFV Orchestration Demo for IoT\n");
    printf("======================================\n");

    NFVOrchestrator orchestrator;
    init_orchestrator(&orchestrator);

    // Define VNF types for smart city service chain
    VNFType smart_city_chain[] = {
        VNF_FIREWALL,
        VNF_DATA_FILTER,
        VNF_ANALYTICS
    };

    // Define VNF types for healthcare service chain
    VNFType healthcare_chain[] = {
        VNF_FIREWALL,
        VNF_ENCRYPTION,
        VNF_INTRUSION_DETECTION,
        VNF_ANALYTICS
    };

    // Create service chains
    create_service_chain(&orchestrator, "SC-001", 
                         smart_city_chain, 3, "SmartCity");

    create_service_chain(&orchestrator, "HC-001", 
                         healthcare_chain, 4, "Healthcare");

    // Display initial resources
    display_resources(&orchestrator);

    // Simulate IoT data processing
    process_iot_data(&orchestrator, "SC-001", 
                     "Traffic sensor: congestion_level=high", 45);

    process_iot_data(&orchestrator, "HC-001", 
                     "Patient monitor: heart_rate=72 spo2=98", 48);

    // Process more data to trigger scaling alert
    process_iot_data(&orchestrator, "SC-001", 
                     "Air quality: pm25=45", 25);
    process_iot_data(&orchestrator, "SC-001", 
                     "Noise level: 65dB", 20);

    // Final resource status
    display_resources(&orchestrator);

    return 0;
}
